using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ---------------------------------------------------------------
    //  AddItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 3, price: 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        _cart.AddItem(null!, quantity: 1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        _cart.AddItem(string.Empty, quantity: 1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_ZeroQuantity_ThrowsArgumentOutOfRangeException()
    {
        _cart.AddItem("SKU-001", quantity: 0, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        _cart.AddItem("SKU-001", quantity: -1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: -1.00m);
    }

    // ---------------------------------------------------------------
    //  RemoveItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_LeavesOtherItems()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        _cart.RemoveItem("NO-SUCH-SKU");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        _cart.RemoveItem(null!);
    }

    // ---------------------------------------------------------------
    //  CalculateTotal
    // ---------------------------------------------------------------

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentItems()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 15.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 7.50m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_HandlesCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1000, price: 99.99m);

        Assert.AreEqual(99_990.00m, _cart.CalculateTotal());
    }

    // ---------------------------------------------------------------
    //  ApplyCoupon
    // ---------------------------------------------------------------

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon(string.Empty);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        _cart.ApplyCoupon("NOT-A-REAL-COUPON");
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ---------------------------------------------------------------
    //  End-to-end scenario
    // ---------------------------------------------------------------

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_ProducesExpectedTotal()
    {
        _cart.AddItem("SKU-A", quantity: 2, price: 25.00m);
        _cart.AddItem("SKU-B", quantity: 1, price: 50.00m);
        _cart.RemoveItem("SKU-B");
        _cart.ApplyCoupon("SAVE10");

        decimal total = _cart.CalculateTotal();

        Assert.IsTrue(total > 0m, "Total should be positive after coupon on non-empty cart.");
        Assert.IsTrue(total < 50.00m, "Total should be less than pre-coupon subtotal of 50.00.");
    }
}

